import React, { useState, useRef, useEffect } from 'react';
import { useCalendar } from '../context/CalendarContext';
import '../styles/ChatInterface.css';

const ChatInterface = () => {
    const [messages, setMessages] = useState([]);
    const [inputValue, setInputValue] = useState('');
    const messagesEndRef = useRef(null);
    const { addTask } = useCalendar();

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const formatAIResponse = (data) => {
        if (data.error) return `Sorry, I couldn't process that. ${data.error}`;
        
        const date = new Date(data.startDate);
        const formattedDate = date.toLocaleDateString('en-US', { 
            weekday: 'long', 
            year: 'numeric', 
            month: 'long', 
            day: 'numeric' 
        });

        return `I've scheduled "${data.title}" for ${formattedDate}. Would you like me to:
1. Add more details to this task
2. Set up a reminder
3. Make it a recurring event`;
    };

    const generateSuggestions = (data) => {
        const suggestions = [
            "Add more details",
            "Set a reminder",
            "Make it recurring"
        ];

        if (data.recurrence) {
            suggestions.push("Change recurrence pattern");
        }

        return suggestions;
    };

    const handleSuggestionClick = (suggestion) => {
        switch (suggestion) {
            case "Add more details":
                setInputValue("Add more details to the task");
                break;
            case "Set a reminder":
                setInputValue("Set a reminder for this task");
                break;
            case "Make it recurring":
                setInputValue("Make this task recurring");
                break;
            default:
                setInputValue(suggestion);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!inputValue.trim()) return;

        // Add user message
        const userMessage = {
            type: 'user',
            content: inputValue,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMessage]);
        setInputValue('');

        try {
            // Send to backend for processing
            const response = await fetch('/api/parse-task', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ input: inputValue })
            });

            const data = await response.json();

            // Add AI response
            const aiMessage = {
                type: 'assistant',
                content: formatAIResponse(data),
                timestamp: new Date(),
                suggestions: generateSuggestions(data)
            };

            setMessages(prev => [...prev, aiMessage]);

            // If the response includes a task, add it to the calendar
            if (data.title && data.startDate) {
                await addTask(data);
            }
        } catch (error) {
            console.error('Error processing message:', error);
            setMessages(prev => [...prev, {
                type: 'assistant',
                content: 'Sorry, I encountered an error processing your request.',
                timestamp: new Date()
            }]);
        }
    };

    return (
        <div className="chat-container">
            <div className="chat-messages">
                {messages.map((message, index) => (
                    <div key={index} className={`message ${message.type}`}>
                        <div className="message-content">{message.content}</div>
                        {message.suggestions && (
                            <div className="message-suggestions">
                                {message.suggestions.map((suggestion, i) => (
                                    <button 
                                        key={i} 
                                        onClick={() => handleSuggestionClick(suggestion)}
                                        className="suggestion-button"
                                    >
                                        {suggestion}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Type your message here..."
                    className="chat-input"
                />
                <button type="submit" className="send-button">
                    <svg viewBox="0 0 24 24" className="send-icon">
                        <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
                    </svg>
                </button>
            </form>
        </div>
    );
};

export default ChatInterface;
